document.querySelector(".content > form").addEventListener("submit",e=>{async function t(){try{const e=await fetch(`${window.location.origin}/api/push`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({long_url:document.querySelector("#pasted_url").value,expiration:document.querySelector("form .expires").getAttribute("data-selected"),user_key:null})}),t=await e.json();if(!e.ok)throw new Error(t.error||"Bad response");if(!0!==t.success)throw new Error(t.response||"Failed to create paste");document.querySelector(".content").classList.add("shortened"),document.querySelector("#pasted_url").value=`${window.location.origin}/${t.response}`}catch(e){console.error("Fetch Error:",e.message)}}e.preventDefault(),t()}),document.addEventListener("click",e=>{e.target.closest(".expires span[data-value]")&&e.target.closest(".expires").setAttribute("data-selected",e.target.closest(".expires span[data-value]").getAttribute("data-value"))});